<?php
$dbHost = 'localhost';
$dbUser = 'root';
$dbPass = '';
$dbName = 'buket_db';

$connection = new mysqli($dbHost, $dbUser, $dbPass);
if ($connection->connect_error) {
    die('Koneksi ke server gagal: ' . $connection->connect_error);
}

if (!$connection->query("CREATE DATABASE IF NOT EXISTS `$dbName` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci")) {
    die('Gagal membuat database: ' . $connection->error);
}

$connection->select_db($dbName);

$queries = [
    "CREATE TABLE IF NOT EXISTS users (
        id INT AUTO_INCREMENT PRIMARY KEY,
        name VARCHAR(100) NOT NULL,
        email VARCHAR(150) NOT NULL UNIQUE,
        password VARCHAR(255) NOT NULL,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4",

    "CREATE TABLE IF NOT EXISTS products (
        id INT AUTO_INCREMENT PRIMARY KEY,
        name VARCHAR(150) NOT NULL,
        description TEXT NOT NULL,
        price INT NOT NULL,
        image_url VARCHAR(255) NOT NULL,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4",

    "INSERT INTO products (name, description, price, image_url) VALUES
        ('Buket Mawar', 'Komposisi bunga mawar segar dengan sentuhan daun hijau lembut.', 150000, 'https://images.unsplash.com/photo-1526045478516-99145907023c?w=900'),
        ('Buket Snack', 'Campuran snack favorit dalam bingkai buket yang unik dan cantik.', 120000, 'data:image/jpeg;base64,'),
        ('Buket Uang', 'Buket elegan yang di desain khusus untuk hadiah bernilai dan berkesan.', 200000, 'https://images.unsplash.com/photo-1519378058457-4c29a0a2efac?w=900'),
        ('Buket Lily', 'Perpaduan lily dan bunga putih untuk nuansa elegan dan tenang.', 180000, 'https://images.unsplash.com/photo-1501004318641-b39e6451bec6?w=900'),
        ('Buket Anniversary', 'Desain romantis khusus untuk momen ulang tahun atau anniversary pasangan.', 220000, 'https://images.unsplash.com/photo-1513558163535-4d7b4967fbe9?w=900'),
        ('Buket Pink Deluxe', 'Campuran bunga pink segar dengan pita mewah, sempurna untuk hadiah istimewa.', 170000, 'https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?w=900'),
        ('Buket Ulang Tahun', 'Buket pesta warna-warni untuk memberikan kejutan meriah kepada orang tersayang.', 135000, 'https://images.unsplash.com/photo-1512436991641-6745cdb1723f?w=900'),
        ('Buket Seruni', 'Gabungan bunga seruni lembut dan daun hijau, cocok untuk ucapan selamat dan syukur.', 165000, 'https://images.unsplash.com/photo-1512917774080-9991f1c4c750?w=900'),
        ('Buket Premium', 'Desain mewah dengan kombinasi bunga premium dan aksen pita emas.', 250000, 'https://images.unsplash.com/photo-1492684223066-81342ee5ff30?w=900')
    "
];

foreach ($queries as $query) {
    if (!$connection->query($query)) {
        die('Gagal menjalankan query: ' . $connection->error);
    }
}

$connection->close();
?>
